query:
-- 找出重複的 email
SELECT email, COUNT(*) as cnt FROM users WHERE email IS NOT NULL GROUP BY email HAVING cnt > 1;

-- 查看所有使用者的 email 狀況
SELECT id, name, email, role, createdAt FROM users ORDER BY email, createdAt;

